import React from 'react';
import './Dashboard.css';

const BalanceSummary = () => {
  // Simplified mock data for demo
  const summary = {
    balance: 12450.00,
    income: 5200.00,
    expenses: 1850.00
  };

  return (
    <div className="summary-grid">
      <div className="summary-card premium-card balance">
        <h3>Total Balance</h3>
        <p className="amount">${summary.balance.toLocaleString()}</p>
      </div>
      <div className="summary-card premium-card income">
        <h3>Monthly Income</h3>
        <p className="amount">${summary.income.toLocaleString()}</p>
      </div>
      <div className="summary-card premium-card expenses">
        <h3>Monthly Expenses</h3>
        <p className="amount">${summary.expenses.toLocaleString()}</p>
      </div>
    </div>
  );
};

export default BalanceSummary;
